import numpy as np

def hierarchical_value_functions(
    num_states: int,
    options: list,
    transitions: dict,
    high_level_policy: dict,
    gamma: float,
    max_iterations: int = 1000,
    tol: float = 1e-8
) -> dict:
    num_options = len(options)
    V = [0.0] * num_states
    Q = [[0.0] * num_options for _ in range(num_states)]

    for _ in range(max_iterations):
        V_old = V[:]
        Q_old = [row[:] for row in Q]

        # Update Q(s, o) for every (state, option) pair
        for s in range(num_states):
            for o_idx, option in enumerate(options):
                a = option['policy'][s]              # primitive action taken by option
                s_next, reward = transitions[(s, a)] # deterministic outcome
                beta = option['termination'][s_next] # P(terminate | arrive at s_next)

                # Bellman eq for options:
                # Q(s,o) = r + gamma * [ beta(s') * V(s') + (1-beta(s')) * Q(s',o) ]
                Q[s][o_idx] = reward + gamma * (
                    beta * V_old[s_next] + (1 - beta) * Q_old[s_next][o_idx]
                )

        # V(s) = Q(s, high_level_policy(s))
        for s in range(num_states):
            V[s] = Q[s][high_level_policy[s]]

        # Convergence check
        max_v_diff = max(abs(V[s] - V_old[s]) for s in range(num_states))
        max_q_diff = max(
            abs(Q[s][o] - Q_old[s][o])
            for s in range(num_states)
            for o in range(num_options)
        )
        if max_v_diff < tol and max_q_diff < tol:
            break

    return {'V': np.array(V), 'Q': np.array(Q)}
